// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/nameservers", wrapper.GetNameservers)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/nameservers", wrapper.CreateNameserver)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/nameservers/{name}", wrapper.DeleteNameserver)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/nameservers/{name}", wrapper.GetNameserver)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/nameservers/{name}", wrapper.ReplaceNameserver)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/resolvers", wrapper.GetResolvers)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/resolvers", wrapper.CreateResolver)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/resolvers/{name}", wrapper.DeleteResolver)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/resolvers/{name}", wrapper.GetResolver)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/resolvers/{name}", wrapper.ReplaceResolver)
	})

	return r
}

